mapper.select:
select n.id, n.type, n.title, n.content, n.data, n.scope, n.user_id, n.user_type, n.notice_type, n.status,
       n.create_by, n.create_time, n.update_by, n.update_time, n.remark,
       case
           when n.scope = 'all' then null
           when n.user_type = 'sys' then su.nick_name
           else pu.nickname
       end as user_nickname
from sys_notification n
left join portal_user pu on n.user_id = pu.id and n.user_type = 'portal'
left join sys_user su on n.user_id = su.user_id and n.user_type = 'sys'

    and n.title like concat('%', #{params.title}, '%')
    and n.type = #{params.type}
    and n.scope = #{params.scope}
    and n.user_type = #{params.userType}
    and n.user_id = #{params.userId}
    and n.status = #{params.status}
    and n.notice_type = #{params.noticeType}
    and n.create_by like concat('%', #{params.createBy}, '%')

order by n.create_time desc



    and title like concat('%', #{params.title}, '%')
    and type = #{params.type}
    and scope = #{params.scope}
    and user_type = #{params.userType}
    and user_id = #{params.userId}
    and status = #{params.status}
    and notice_type = #{params.noticeType}
    and create_by like concat('%', #{params.createBy}, '%')

order by create_time desc

mapper.update:
update sys_notification
type = #{type}, title = #{title}, content = #{content}, data = #{data}, scope = #{scope}, user_id = #{userId}, user_type = #{userType}, notice_type = #{noticeType}, status = #{status}, update_by = #{updateBy}, update_time = #{updateTime}, remark = #{remark},
where id = #{id}

mapper.select:
select count(*)
from sys_notification n
where n.status = '0'
and (
    (n.scope = 'user' and n.user_id = #{userId} and n.user_type = #{userType})
    or n.scope = 'all'
)
and not exists (
    select 1 from sys_notification_read r
    where r.notification_id = n.id
      and r.user_id = #{userId}
      and r.user_type = #{userType}
)
